import { useState, useRef, useCallback, useEffect, memo } from "react";
import { useLocation } from "react-router-dom";
import { Music, Music2 } from "lucide-react";
import { useQuery } from "@tanstack/react-query";
import { supabase } from "@/integrations/supabase/client";

const STORAGE_KEY = "hero-music-pref";
const FADE_MS = 350; // gentle crossfade duration
const TARGET_VOLUME = 0.85;
const FALLBACK_TRACKS = [
  "/music/blues1.mp3",
  "/music/blues2.mp3",
  "/music/blues3.mp3",
  "/music/blues4.mp3",
  "/music/blues5.mp3",
  "/music/blues6.mp3",
];

interface HeroMusicButtonProps {
  className?: string;
}

const HeroMusicButton = memo(({ className = "" }: HeroMusicButtonProps) => {
  const location = useLocation();
  const [isPlaying, setIsPlaying] = useState(false);
  const audioRef = useRef<HTMLAudioElement | null>(null);
  const trackIndexRef = useRef(0);
  const isPlayingRef = useRef(false);
  const autoplayAttemptedRef = useRef(false);
  const fadeTimerRef = useRef<number | null>(null);
  const duckedRef = useRef(false); // true while a video is playing
  const wasPlayingBeforeDuckRef = useRef(false);

  // Hide music button entirely while user is composing (it overlaps editors)
  const hidden = location.pathname.startsWith("/community/create");

  const { data: dbTracks } = useQuery({
    queryKey: ["background-music"],
    queryFn: async () => {
      const { data } = await supabase
        .from("background_music")
        .select("file_url")
        .eq("is_active", true)
        .order("sort_order");
      return data?.map((t) => t.file_url) || [];
    },
    staleTime: 10 * 60 * 1000,
  });

  const tracks = dbTracks && dbTracks.length > 0 ? dbTracks : FALLBACK_TRACKS;

  const shuffledTracksRef = useRef<string[]>([]);
  useEffect(() => {
    const shuffled = [...tracks].sort(() => Math.random() - 0.5);
    shuffledTracksRef.current = shuffled;
    trackIndexRef.current = 0;
  }, [tracks]);

  const clearFade = () => {
    if (fadeTimerRef.current !== null) {
      window.clearInterval(fadeTimerRef.current);
      fadeTimerRef.current = null;
    }
  };

  /** Fade audio volume to target over FADE_MS, then call onDone. */
  const fadeTo = useCallback((target: number, onDone?: () => void) => {
    const audio = audioRef.current;
    if (!audio) { onDone?.(); return; }
    clearFade();
    const start = audio.volume;
    const startTs = performance.now();
    fadeTimerRef.current = window.setInterval(() => {
      const audioNow = audioRef.current;
      if (!audioNow) { clearFade(); onDone?.(); return; }
      const t = Math.min(1, (performance.now() - startTs) / FADE_MS);
      audioNow.volume = Math.max(0, Math.min(1, start + (target - start) * t));
      if (t >= 1) {
        clearFade();
        onDone?.();
      }
    }, 30);
  }, []);

  useEffect(() => {
    return () => {
      isPlayingRef.current = false;
      clearFade();
      const audio = audioRef.current;
      if (audio) {
        audio.onended = null;
        audio.onerror = null;
        audio.pause();
        audio.removeAttribute("src");
        audio.load();
        audioRef.current = null;
      }
    };
  }, []);

  const consecutiveErrorsRef = useRef(0);
  const MAX_CONSECUTIVE_ERRORS = 3;

  const stopAudio = useCallback(() => {
    isPlayingRef.current = false;
    setIsPlaying(false);
    clearFade();
    const audio = audioRef.current;
    if (audio) {
      audio.onended = null;
      audio.onerror = null;
      audio.pause();
      audio.removeAttribute("src");
      audio.load();
      audioRef.current = null;
    }
  }, []);

  const playTrack = useCallback((index: number) => {
    const list = shuffledTracksRef.current;
    if (list.length === 0) return;
    if (!isPlayingRef.current) return;
    if (consecutiveErrorsRef.current >= MAX_CONSECUTIVE_ERRORS) {
      stopAudio();
      consecutiveErrorsRef.current = 0;
      return;
    }
    const idx = index % list.length;
    trackIndexRef.current = idx;
    const audio = audioRef.current;
    if (!audio) { stopAudio(); return; }
    audio.pause();
    audio.src = list[idx];
    audio.onended = () => {
      consecutiveErrorsRef.current = 0;
      if (isPlayingRef.current) playTrack(idx + 1);
    };
    audio.onerror = () => {
      consecutiveErrorsRef.current += 1;
      if (isPlayingRef.current) playTrack(idx + 1);
    };
    const doPlay = () => {
      if (!isPlayingRef.current) return;
      audio.volume = 0;
      audio.play()
        .then(() => fadeTo(duckedRef.current ? 0 : TARGET_VOLUME))
        .catch(() => stopAudio());
    };
    if (audio.readyState >= 2) {
      doPlay();
    } else {
      audio.oncanplay = () => { audio.oncanplay = null; doPlay(); };
      audio.load();
    }
  }, [stopAudio, fadeTo]);

  const startPlayback = useCallback(() => {
    if (isPlayingRef.current) return;
    const list = shuffledTracksRef.current;
    if (list.length === 0) return;

    isPlayingRef.current = true;
    setIsPlaying(true);
    consecutiveErrorsRef.current = 0;

    const listLength = list.length;
    let startIndex = Math.floor(Math.random() * listLength);
    const previousIndex = trackIndexRef.current;
    if (listLength > 1 && startIndex === previousIndex) {
      startIndex = (startIndex + 1) % listLength;
    }
    trackIndexRef.current = startIndex;

    const audio = new Audio();
    audio.volume = 0; // start silent → fade in
    audio.crossOrigin = "anonymous";
    audio.preload = "auto";
    audioRef.current = audio;

    const idx = startIndex % listLength;
    audio.src = list[idx];

    audio.onended = () => {
      consecutiveErrorsRef.current = 0;
      if (isPlayingRef.current) playTrack(idx + 1);
    };
    audio.onerror = () => {
      consecutiveErrorsRef.current += 1;
      if (isPlayingRef.current) playTrack(idx + 1);
    };

    return audio.play().then(() => {
      try { localStorage.setItem(STORAGE_KEY, "on"); } catch {}
      fadeTo(duckedRef.current ? 0 : TARGET_VOLUME);
    }).catch((err) => {
      if (err.name === "NotSupportedError" || err.name === "TypeError") {
        consecutiveErrorsRef.current += 1;
        if (isPlayingRef.current) playTrack(startIndex + 1);
        return;
      }
      stopAudio();
      throw err;
    });
  }, [playTrack, stopAudio, fadeTo]);

  /** Auto-play on mount */
  useEffect(() => {
    if (autoplayAttemptedRef.current) return;
    if (shuffledTracksRef.current.length === 0) return;
    autoplayAttemptedRef.current = true;
    try { if (localStorage.getItem(STORAGE_KEY) === "off") return; } catch {}

    const tryAutoplay = startPlayback();
    if (tryAutoplay) {
      tryAutoplay.catch(() => {
        const onFirstInteraction = () => {
          document.removeEventListener("click", onFirstInteraction, true);
          document.removeEventListener("touchstart", onFirstInteraction, true);
          if (isPlayingRef.current) return;
          try { if (localStorage.getItem(STORAGE_KEY) === "off") return; } catch {}
          startPlayback()?.catch(() => {});
        };
        document.addEventListener("click", onFirstInteraction, true);
        document.addEventListener("touchstart", onFirstInteraction, true);
      });
    }
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [tracks]);

  /**
   * Global video ducking: any <video> element on the page that starts playing
   * fades the music down (to 0) and pauses it; when ALL videos are paused/ended
   * the music fades back in from where it was.
   */
  useEffect(() => {
    const playingVideos = new Set<HTMLVideoElement>();

    const duck = () => {
      if (duckedRef.current) return;
      duckedRef.current = true;
      wasPlayingBeforeDuckRef.current = isPlayingRef.current;
      const audio = audioRef.current;
      if (audio && isPlayingRef.current) {
        fadeTo(0, () => {
          // Pause only after fade finishes, and only if still ducked
          if (duckedRef.current && audioRef.current) audioRef.current.pause();
        });
      }
    };

    const unduck = () => {
      if (!duckedRef.current) return;
      duckedRef.current = false;
      if (!wasPlayingBeforeDuckRef.current) return;
      const audio = audioRef.current;
      if (audio) {
        audio.volume = 0;
        audio.play().then(() => fadeTo(TARGET_VOLUME)).catch(() => {});
      } else if (!isPlayingRef.current) {
        startPlayback()?.catch(() => {});
      }
    };

    const onPlay = (e: Event) => {
      const v = e.target as HTMLVideoElement;
      if (!(v instanceof HTMLVideoElement)) return;
      // Ignore muted background videos (e.g. hero looping previews)
      if (v.muted) return;
      playingVideos.add(v);
      duck();
    };
    const onPauseOrEnd = (e: Event) => {
      const v = e.target as HTMLVideoElement;
      if (!(v instanceof HTMLVideoElement)) return;
      playingVideos.delete(v);
      if (playingVideos.size === 0) unduck();
    };

    document.addEventListener("play", onPlay, true);
    document.addEventListener("pause", onPauseOrEnd, true);
    document.addEventListener("ended", onPauseOrEnd, true);
    return () => {
      document.removeEventListener("play", onPlay, true);
      document.removeEventListener("pause", onPauseOrEnd, true);
      document.removeEventListener("ended", onPauseOrEnd, true);
    };
  }, [fadeTo, startPlayback]);

  const toggleMusic = useCallback(() => {
    if (isPlayingRef.current) {
      // Manual pause: fade out then stop
      fadeTo(0, () => stopAudio());
      try { localStorage.setItem(STORAGE_KEY, "off"); } catch {}
    } else {
      startPlayback()?.catch(() => {});
    }
  }, [startPlayback, stopAudio, fadeTo]);

  if (hidden) return null;

  return (
    <button
      onClick={toggleMusic}
      className={`group w-8 h-8 rounded-full flex items-center justify-center transition-all duration-300 shadow-lg cursor-pointer bg-primary text-primary-foreground hover:bg-primary/90 ${
        isPlaying ? "ring-2 ring-primary/50 animate-pulse" : ""
      } ${className}`}
      aria-label={isPlaying ? "Mute background music" : "Play background music"}
    >
      {isPlaying ? (
        <Music className="w-4 h-4 drop-shadow-sm" />
      ) : (
        <Music2 className="w-4 h-4 group-hover:scale-110 transition-transform" />
      )}
    </button>
  );
});

HeroMusicButton.displayName = "HeroMusicButton";

export default HeroMusicButton;
